create table dirkspzm32.edi_vda4987_ipig (
    document_id             varchar2(32 char) not null enable,
    ipig_id                 varchar2(32 char) not null enable,
    pos                     number(4, 0) not null enable,
    package_qty             number(6, 0),
    terms_and_cond_code     varchar2(3 char),
    pack_type_desc_code     varchar2(7 char),
    type_of_packages        varchar2(35 char),
    gross_weight_in_kg      number(7, 0),
    net_weight_in_kg        number(7, 0),
    tare_weight_in_kg       number(7, 0),
    volume_of_pack_material number(9, 0),
    volume_measurement_unit varchar2(8 char),
    maximum_stackability    number(3, 0),
    qty_per_packaging_unit  number(6, 0)
);

alter table dirkspzm32.edi_vda4987_ipig
    add constraint pk_edi_vda4987_ipig primary key ( ipig_id )
        using index enable;


